import { useState } from 'react';
//import { format } from 'date-fns';
import './App.css';
import Api from './axios/api';

interface Usuario {
  id: number;
  nome: string;
  cpf: string;
  telefone: string;
  dia_agendado: string;
  hora_agendada:string;
  data:string;
  //status: string;
}

function App() {
const [usuarios, setUsuarios] =useState<Usuario[]>([{} as Usuario]);
 //const formattedDate = format(new Dat), 'dd,MM, yyyy ');
const BuscarTodosUsuarios= async () => {
  console.log("Buscando todos os usuários...");
 await Api.get("",{
    params:{
    planilha:"usuario"
  }
  }
).then((response)=>setUsuarios(response.data) )  
  .catch((e)=> console.log(e));
  console.log("Usuários encontrados:", usuarios);

}
return (
    <div style={{display:'flex',flexDirection:"column"}}>
      <h1>Hello Mumi Braids!</h1>
      <h4> Site de Agendamento</h4>      
   <table border={1} width="80%" style={{margin:10}} summary='Tabela de usuários'>
<thead>
 <tr>
    <th>Nome</th>     
    <th>CPF</th>
    <th>Telefone</th>
    <th>Dia Agendado</th>
    <th>Hora Agendada</th>
    <th>Data</th>  
    </tr>
</thead>
<tbody>
  {usuarios.map((usuario) => (   
    <tr>    
      <td>{usuario.nome}</td>
      <td>{usuario.cpf}</td>
      <td>{usuario.telefone}</td>
      <td>{usuario.dia_agendado}</td>
      <td>{usuario.hora_agendada}</td>   
      <td>{usuario.data}</td>   
      </tr>    
  ))}
</tbody>
   </table>
    <div>
      <button onClick={BuscarTodosUsuarios}>  Visuaisar</button>
      </div>
<div >
      <form style={{display:"flex",flexDirection: "column" ,width:"50%",margin:10}}>
    <input type="text" placeholder='Nome' />
    <input type="text" placeholder='CPF' />
    <input type="text" placeholder='Telefone' />
    <input type="text" placeholder='Dia Agendado' />
    <input type="text" placeholder='Hora Agendada' />
    <input type="text" placeholder='Data' />
    <button type="submit">Cadastrar</button>
    <button type="reset">Limpar</button>
  </form>
</div>

    </div> 
  );
}

export default App;
